import json
import os
from datetime import datetime

def lambda_handler(event, context):
    # Validate request method
    http_method = event.get('httpMethod', '')
    
    # Security: Validate origin against whitelist
    allowed_origins = os.environ.get('ALLOWED_ORIGINS', '').split(',')
    request_origin = event.get('headers', {}).get('origin', '') or event.get('headers', {}).get('Origin', '')
    
    # Security: Only allow specific origins, not wildcard
    if not allowed_origins or allowed_origins == ['']:
        allowed_origins = [
            'http://localhost:3000',
            'http://localhost:8080',
            'https://staging.yourdomain.com',
            'https://yourdomain.com'
        ]
    
    # Determine if origin is allowed
    origin_allowed = request_origin in allowed_origins
    response_origin = request_origin if origin_allowed else allowed_origins[0]
    
    # Security headers
    headers = {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': response_origin,
        'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token',
        'Access-Control-Max-Age': '3600',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'X-XSS-Protection': '1; mode=block',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        'Content-Security-Policy': "default-src 'self'"
    }
    
    # Handle preflight OPTIONS request
    if http_method == 'OPTIONS':
        return {
            'statusCode': 200,
            'headers': headers,
            'body': ''
        }
    
    # Handle GET request
    if http_method == 'GET':
        # Security: Input validation for query parameters
        query_params = event.get('queryStringParameters') or {}
        user_id = query_params.get('userId', '')
        
        # Security: Validate user_id format (alphanumeric only)
        if user_id and not user_id.isalnum():
            return {
                'statusCode': 400,
                'headers': headers,
                'body': json.dumps({
                    'error': 'Invalid user ID format',
                    'message': 'User ID must be alphanumeric'
                })
            }
        
        # Mock user data (replace with actual database query)
        user_data = {
            'userId': user_id or 'user123',
            'username': 'john_doe',
            'email': 'john@example.com',
            'firstName': 'John',
            'lastName': 'Doe',
            'role': 'user',
            'createdAt': '2024-01-01T00:00:00Z',
            'lastLogin': datetime.utcnow().isoformat() + 'Z',
            'isActive': True
        }
        
        return {
            'statusCode': 200,
            'headers': headers,
            'body': json.dumps(user_data)
        }
    
    # Handle POST request
    if http_method == 'POST':
        try:
            # Security: Validate request body
            body = event.get('body', '{}')
            if isinstance(body, str):
                data = json.loads(body)
            else:
                data = body
            
            # Security: Input validation and sanitization
            required_fields = ['username', 'email']
            for field in required_fields:
                if field not in data:
                    return {
                        'statusCode': 400,
                        'headers': headers,
                        'body': json.dumps({
                            'error': 'Missing required field',
                            'field': field
                        })
                    }
            
            # Security: Validate email format
            email = data.get('email', '')
            if '@' not in email or '.' not in email.split('@')[-1]:
                return {
                    'statusCode': 400,
                    'headers': headers,
                    'body': json.dumps({
                        'error': 'Invalid email format'
                    })
                }
            
            # Security: Limit username length
            username = data.get('username', '')
            if len(username) > 50 or len(username) < 3:
                return {
                    'statusCode': 400,
                    'headers': headers,
                    'body': json.dumps({
                        'error': 'Username must be between 3 and 50 characters'
                    })
                }
            
            # Mock response (replace with actual database operation)
            response_data = {
                'success': True,
                'userId': 'user' + str(hash(username))[-6:],
                'username': username,
                'email': email,
                'createdAt': datetime.utcnow().isoformat() + 'Z'
            }
            
            return {
                'statusCode': 201,
                'headers': headers,
                'body': json.dumps(response_data)
            }
            
        except json.JSONDecodeError:
            return {
                'statusCode': 400,
                'headers': headers,
                'body': json.dumps({
                    'error': 'Invalid JSON in request body'
                })
            }
        except Exception as e:
            # Security: Don't expose internal errors
            return {
                'statusCode': 500,
                'headers': headers,
                'body': json.dumps({
                    'error': 'Internal server error'
                })
            }
    
    # Method not allowed
    return {
        'statusCode': 405,
        'headers': headers,
        'body': json.dumps({
            'error': 'Method not allowed',
            'allowedMethods': ['GET', 'POST', 'OPTIONS']
        })
    }